// From mcpTools.js lines 23-119
class MCPHttpClient extends EventEmitter {
  async request(method, params = {}) {
    const body = {
      jsonrpc: '2.0',
      method,
      params,
      id: this.requestId++,
    };

    const response = await fetch(this.url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify(body),
    });

    const result = await response.json();
    if (result.error) {
      throw new Error(result.error.message || result.error.code);
    }
    return result.result;
  }
}
```

#### Stdio Transport (NDJSON Framing)
```javascript
// From mcpTools.js lines 124-304
class MCPStdioClient extends EventEmitter {
  start() {
    return new Promise((resolve, reject) => {
      this.process = spawn(this.command, this.args, {
        stdio: ['pipe', 'pipe', 'pipe'],
        env: { ...process.env, ...this.env },
      });

      this.process.stdout.on('data', (data) => {
        this.buffer += data.toString();
        this.processBuffer();  // NDJSON parsing
      });
    });
  }

  // Newline-delimited JSON framing
  processBuffer() {
    const lines = this.buffer.split('\n');
    this.buffer = lines.pop() || '';  // Keep incomplete line

    for (const line of lines) {
      if (line.trim()) {
        try {
          const message = JSON.parse(line);
          this.handleMessage(message);
        } catch (e) { /* Not JSON, ignore */ }
      }
    }
  }
}
```

### рҹ”„ Connection Lifecycle

```javascript
// From mcpTools.js lines 319-395
const mcpConnect = {
  name: 'mcp_connect',
  async execute({ name, type, url, command, args = [], env = {} }) {
    if (mcpConnections.has(name)) {
      return { success: false, error: `Connection "${name}" already exists` };
    }

    let client;

    if (type === 'http') {
      client = new MCPHttpClient(url);
      await client.initialize();
    } else if (type === 'stdio') {
      client = new MCPStdioClient(command, args, env);
      await client.start();
      await client.initialize();
    }

    mcpConnections.set(name, client);

    return {
      success: true,
      name,
      type,
      serverInfo: client.serverInfo,
    };
  }
};
```

